package org.example.MultiLevelParkingLot;

import org.example.MultiLevelParkingLot.Spots.ParkingSpot;
import org.example.MultiLevelParkingLot.Vehicle.Vehicle;
import org.example.ParkingLot.FareCa.FareCalculator;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

/**
 * Main class for managing a multi-level parking lot system.
 * Handles vehicle entry, exit, and fare calculation across multiple levels.
 * This is the main entry point for parking lot operations.
 */
public class MultiLevelParkingLot {
    private final MultiLevelManager multiLevelManager;
    private final FareCalculator fareCalculator;

    /**
     * Initializes a multi-level parking lot with a manager and fare calculator.
     *
     * @param multiLevelManager Manager that handles all levels
     * @param fareCalculator Calculator for determining parking fees
     */
    public MultiLevelParkingLot(MultiLevelManager multiLevelManager, FareCalculator fareCalculator) {
        this.multiLevelManager = multiLevelManager;
        this.fareCalculator = fareCalculator;
    }

    /**
     * Processes vehicle entry into the parking lot.
     * Finds an appropriate level and spot, then issues a ticket.
     * This method is called when a vehicle enters the parking lot.
     *
     * @param vehicle The vehicle entering the lot
     * @return MultiLevelTicket if parking was successful, null if lot is full
     */
    public MultiLevelTicket entryVehicle(Vehicle vehicle) {
        Level level = multiLevelManager.findLevelForVehicle(vehicle);
        if (level != null) {
            ParkingSpot parkingSpot = level.parkVehicle(vehicle);
            if (parkingSpot != null) {
                String ticketId = generateTicketId();
                MultiLevelTicket ticket = new MultiLevelTicket(
                        ticketId, vehicle, parkingSpot, level, LocalDateTime.now());
                return ticket;
            }
        }
        return null; // Parking lot is full
    }

    /**
     * Processes vehicle exit from the parking lot.
     * Calculates fare, unpacks the vehicle, and displays payment information.
     * This method is called when a vehicle exits the parking lot.
     *
     * @param ticket The parking ticket presented at exit
     */
    public void leaveVehicle(MultiLevelTicket ticket) {
        if (ticket != null && ticket.getExitTime() == null) {
            // Set exit time
            ticket.setExitTime(LocalDateTime.now());

            // Unpark the vehicle from the level
            multiLevelManager.unparkVehicle(ticket.getVehicle());

            // Calculate fare using FareCalculator
            BigDecimal fare = fareCalculator.calculateFare(
                    new org.example.ParkingLot.Ticket(
                            ticket.getTicketId(),
                            ticket.getVehicle(),
                            ticket.getParkingSpot(),
                            ticket.getEntryTime()));
            fare = fare.add(calculateLevelSurcharge(ticket.getLevel()));

            // Display payment information
            System.out.println("==================================");
            System.out.println("Vehicle Exit Receipt");
            System.out.println("==================================");
            System.out.println("Ticket ID: " + ticket.getTicketId());
            System.out.println("License Plate: " + ticket.getVehicle().getLicensePlate());
            System.out.println("Level: " + ticket.getLevel().getLevelNumber());
            System.out.println("Spot: " + ticket.getParkingSpot().getSpotNumber());
            System.out.println("Entry Time: " + ticket.getEntryTime());
            System.out.println("Exit Time: " + ticket.getExitTime());
            System.out.println("Duration: " + ticket.calculateParkingDuration() + " minutes");
            System.out.println("Total Fare: $" + fare);
            System.out.println("==================================");
        } else {
            System.out.println("Invalid ticket or vehicle already exited.");
        }
    }

    /**
     * Calculates surcharge based on the parking level.
     * Higher levels may have different pricing.
     * This allows for premium pricing on upper levels.
     *
     * @param level The level where vehicle was parked
     * @return Surcharge amount as BigDecimal
     */
    private BigDecimal calculateLevelSurcharge(Level level) {
        // Example: Higher levels have higher surcharge
        // Level 1 = $0, Level 2 = $1, Level 3 = $2, etc.
        return new BigDecimal(Math.max(0, level.getLevelNumber() - 1));
    }

    /**
     * Generates a unique ticket ID based on timestamp.
     *
     * @return Unique ticket identifier
     */
    private String generateTicketId() {
        return "TICKET-" + System.currentTimeMillis();
    }

    /**
     * Gets the current occupancy status of the entire parking lot.
     *
     * @return String representation of parking lot status
     */
    public String getParkingLotStatus() {
        return multiLevelManager.getOccupancyStatus();
    }

    /**
     * Gets the total available parking spots in the entire lot.
     *
     * @return Number of available spots
     */
    public int getTotalAvailableSpots() {
        return multiLevelManager.getTotalAvailableSpots();
    }

    /**
     * Checks if the entire parking lot is full.
     *
     * @return true if no spots available in any level
     */
    public boolean isParkingLotFull() {
        return multiLevelManager.isFull();
    }

    /**
     * Gets the total number of levels in this parking lot.
     *
     * @return Number of levels
     */
    public int getTotalLevels() {
        return multiLevelManager.getTotalLevels();
    }
}

package org.example.MultiLevelParkingLot;

import org.example.MultiLevelParkingLot.Spots.ParkingSpot;
import org.example.MultiLevelParkingLot.Vehicle.Vehicle;
import org.example.ParkingLot.FareCa.FareCalculator;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

/**
 * Main class for managing a multi-level parking lot system.
 * Handles vehicle entry, exit, and fare calculation across multiple levels.
 * This is the main entry point for parking lot operations.
 */
public class MultiLevelParkingLot {
    private final MultiLevelManager multiLevelManager;
    private final FareCalculator fareCalculator;

    /**
     * Initializes a multi-level parking lot with a manager and fare calculator.
     *
     * @param multiLevelManager Manager that handles all levels
     * @param fareCalculator Calculator for determining parking fees
     */
    public MultiLevelParkingLot(MultiLevelManager multiLevelManager, FareCalculator fareCalculator) {
        this.multiLevelManager = multiLevelManager;
        this.fareCalculator = fareCalculator;
    }

    /**
     * Processes vehicle entry into the parking lot.
     * Finds an appropriate level and spot, then issues a ticket.
     * This method is called when a vehicle enters the parking lot.
     *
     * @param vehicle The vehicle entering the lot
     * @return MultiLevelTicket if parking was successful, null if lot is full
     */
    public MultiLevelTicket entryVehicle(Vehicle vehicle) {
        Level level = multiLevelManager.findLevelForVehicle(vehicle);
        if (level != null) {
            ParkingSpot parkingSpot = level.parkVehicle(vehicle);
            if (parkingSpot != null) {
                String ticketId = generateTicketId();
                MultiLevelTicket ticket = new MultiLevelTicket(
                        ticketId, vehicle, parkingSpot, level, LocalDateTime.now());
                return ticket;
            }
        }
        return null; // Parking lot is full
    }

    /**
     * Processes vehicle exit from the parking lot.
     * Calculates fare, unpacks the vehicle, and displays payment information.
     * This method is called when a vehicle exits the parking lot.
     *
     * @param ticket The parking ticket presented at exit
     */
    public void leaveVehicle(MultiLevelTicket ticket) {
        if (ticket != null && ticket.getExitTime() == null) {
            // Set exit time
            ticket.setExitTime(LocalDateTime.now());

            // Unpark the vehicle from the level
            multiLevelManager.unparkVehicle(ticket.getVehicle());

            // Calculate fare using FareCalculator
            // Note: Creating a wrapper ticket for fare calculation with single-level Vehicle interface
            org.example.ParkingLot.Ticket singleLevelTicket = 
                    new org.example.ParkingLot.Ticket(
                            ticket.getTicketId(),
                            convertToSingleLevelVehicle(ticket.getVehicle()),
                            ticket.getParkingSpot(),
                            ticket.getEntryTime());
            BigDecimal fare = fareCalculator.calculateFare(singleLevelTicket);
            fare = fare.add(calculateLevelSurcharge(ticket.getLevel()));

            // Display payment information
            System.out.println("==================================");
            System.out.println("Vehicle Exit Receipt");
            System.out.println("==================================");
            System.out.println("Ticket ID: " + ticket.getTicketId());
            System.out.println("License Plate: " + ticket.getVehicle().getLicensePlate());
            System.out.println("Level: " + ticket.getLevel().getLevelNumber());
            System.out.println("Spot: " + ticket.getParkingSpot().getSpotNumber());
            System.out.println("Entry Time: " + ticket.getEntryTime());
            System.out.println("Exit Time: " + ticket.getExitTime());
            System.out.println("Duration: " + ticket.calculateParkingDuration() + " minutes");
            System.out.println("Total Fare: $" + fare);
            System.out.println("==================================");
        } else {
            System.out.println("Invalid ticket or vehicle already exited.");
        }
    }

    /**
     * Calculates surcharge based on the parking level.
     * Higher levels may have different pricing.
     * This allows for premium pricing on upper levels.
     *
     * @param level The level where vehicle was parked
     * @return Surcharge amount as BigDecimal
     */
    private BigDecimal calculateLevelSurcharge(Level level) {
        // Example: Higher levels have higher surcharge
        // Level 1 = $0, Level 2 = $1, Level 3 = $2, etc.
        return new BigDecimal(Math.max(0, level.getLevelNumber() - 1));
    }

    /**
     * Generates a unique ticket ID based on timestamp.
     *
     * @return Unique ticket identifier
     */
    private String generateTicketId() {
        return "TICKET-" + System.currentTimeMillis();
    }

    /**
     * Gets the current occupancy status of the entire parking lot.
     *
     * @return String representation of parking lot status
     */
    public String getParkingLotStatus() {
        return multiLevelManager.getOccupancyStatus();
    }

    /**
     * Gets the total available parking spots in the entire lot.
     *
     * @return Number of available spots
     */
    public int getTotalAvailableSpots() {
        return multiLevelManager.getTotalAvailableSpots();
    }

    /**
     * Checks if the entire parking lot is full.
     *
     * @return true if no spots available in any level
     */
    public boolean isParkingLotFull() {
        return multiLevelManager.isFull();
    }

    /**
     * Gets the total number of levels in this parking lot.
     *
     * @return Number of levels
     */
    public int getTotalLevels() {
        return multiLevelManager.getTotalLevels();
    }
}
